export const getSearchYelpUrl = (params?: SearchYelpParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/yelp/search?${stringifiedParams}` : `/api/yelp/search`
}

/**
 * @summary Search Yelp for food spots in New Orleans
 */
export const searchYelp = async (params?: SearchYelpParams, options?: RequestInit): Promise<YelpSearchResult> => {

  return customFetch<YelpSearchResult>(getSearchYelpUrl(params),
  {
    ...options,
    method: 'GET'


  }
);}





